  return c.json({
    status: "healthy",
    version: BUILD_INFO.version,
    commit: BUILD_INFO.commit,
    uptime: getUptime(),
    startedAt: getStartupTime().toISOString(),
    environment: process.env.NODE_ENV || "development",
    timestamp: new Date().toISOString(),
    capabilities: getCapabilities(),
    correlationId: getCorrelationId(),
  });
});
```

### 5. Detailed Readiness Check (Optional Enhancement)
```typescript
health.get("/ready", async (c) => {
  const checks = {
    database: await checkDatabase(),
    drivers: checkDrivers(),
    mail: await checkMailService(),
    dcg: await checkDCG(),
  };

  const allPass = Object.values(checks).every((c) => c.status === "pass");
  const anyFail = Object.values(checks).some((c) => c.status === "fail");

  return c.json({
    status: anyFail ? "unhealthy" : allPass ? "ready" : "degraded",
    version: BUILD_INFO.version,
    uptime: getUptime(),
    checks,
    timestamp: new Date().toISOString(),
  }, anyFail ? 503 : 200);
});
```

